1	import {
2	  quote,
3	  claim,
4	  insuranceValueFor,
5	  isKnownItemType,
6	  type Customer,
7	  type Item,
8	  type Policy,
9	  type Incident,
10	} from "./claim-office.js";
11	
12	const CAP_MULTIPLIER = 2;
13	
14	type QuoteStep = {
15	  op: "quote";
16	  items: Item[];
17	};
18	
19	type ClaimStep = {
20	  op: "claim";
21	  policy: number;
22	  incident: Incident;
23	};
24	
25	type Step = QuoteStep | ClaimStep;
26	
27	type Scenario = {
28	  customer: Customer;
29	  steps: Step[];
30	};
31	
32	const readStdin = async (): Promise<string> => {
33	  const chunks: Buffer[] = [];
34	  for await (const chunk of process.stdin) {
35	    chunks.push(chunk as Buffer);
36	  }
37	  return Buffer.concat(chunks).toString("utf8");
38	};
39	
40	const policyCapFor = (items: Item[]): number =>
41	  items.reduce((sum, item) => sum + CAP_MULTIPLIER * insuranceValueFor(item), 0);
42	
43	const validateQuoteItems = (items: Item[]): void => {
44	  const unknown = items.find((item) => !isKnownItemType(item.type));
45	  if (unknown) throw new Error(`Unknown item type: ${unknown.type}`);
46	};
47	
48	const validateClaimDamages = (policy: Policy, damages: Incident["damages"]): void => {
49	  const uncovered = damages.find(
50	    (damage) => !policy.items.some((item) => item.type === damage.itemType),
51	  );
52	  if (uncovered) throw new Error(`Damage references item not in policy: ${uncovered.itemType}`);
53	};
54	
55	const handleQuote = (
56	  customer: Customer,
57	  step: QuoteStep,
58	  policies: Policy[],
59	): unknown => {
60	  validateQuoteItems(step.items);
61	  const result = quote({ customer, items: step.items });
62	  policies.push({ items: step.items, remainingCap: policyCapFor(step.items) });
63	  return result;
64	};
65	
66	const handleClaim = (step: ClaimStep, policies: Policy[]): unknown => {
67	  const policy = policies[step.policy];
68	  validateClaimDamages(policy, step.incident.damages);
69	  const result = claim({ policy, incident: step.incident });
70	  policy.remainingCap = result.remainingCap;
71	  return result;
72	};
73	
74	const runStep = (
75	  customer: Customer,
76	  step: Step,
77	  policies: Policy[],
78	): unknown =>
79	  step.op === "quote"
80	    ? handleQuote(customer, step, policies)
81	    : handleClaim(step, policies);
82	
83	const runScenario = (scenario: Scenario): unknown[] => {
84	  const policies: Policy[] = [];
85	  return scenario.steps.map((step) => runStep(scenario.customer, step, policies));
86	};
87	
88	const main = async () => {
89	  const input = await readStdin();
90	  const scenario: Scenario = JSON.parse(input);
91	  const results = runScenario(scenario);
92	  process.stdout.write(JSON.stringify({ results }));
93	};
94	
95	main().catch((err) => {
96	  process.stderr.write(String(err));
97	  process.exit(1);
98	});
